var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"저기, 인형들이 아까보다 더 커진 것 같지 않아?","JPN":"ねえ、人形の大きさがさっきより大きくなってない？","ENG":"Hey, don't those dolls look bigger than before?","TWN":"你看，那些人偶是不是變大了？"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"움직임도 전보다 빨라졌어요.","JPN":"動きも速くなりました。","ENG":"Their movements are faster than before as well.","TWN":"動作也變快了。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"산 정상의 빛이... 아까보다 밝아진 영향인 것 같네요.","JPN":"山の頂上の光が……さっきより明るくなった影響のようですね。","ENG":"The light at the summit... it seems to have grown brighter than earlier.","TWN":"山頂的光……比剛才更亮了。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"더 밝아졌다니, 저 안에서 무슨 일이 벌어지고 있는 거야?","JPN":"もっと明るくなったって……あの中で何が起きてるの？","ENG":"If it's gotten brighter, what's happening inside there?","TWN":"更亮的話，是不是代表裡面發生了什麼事？"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"설마... 실패한 건 아니겠지?","JPN":"まさか……失敗したんじゃないよね？","ENG":"No way... they didn't fail, did they?","TWN":"該不會……失敗了吧？"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 방금 뭐죠? 무전 소리가 들린 것 같았는데.","JPN":"あっ、今の音は何ですか？　無線の音が聞こえた気がしましたけど。","ENG":"Huh? What was that just now? I thought I heard something over the comms.","TWN":"咦？剛才是不是有通訊聲？"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"잘못 들은 거겠지. 이 일대는 침식파와 신성 파장에 장악 당하고 있어.","JPN":"聞き間違いだろう。この一帯は侵食波と神聖波長に掌握されている。","ENG":"You must've misheard. This entire area is being overwhelmed by Corruption rays and Divinity energy.","TWN":"應該聽錯了吧，這一帶被侵蝕波與神性壓制了波長。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"통신 센서가 작동할 리가...","JPN":"通信センサーが機能するわけ……","ENG":"There's no way the communication sensors would be working...","TWN":"通訊不可能運作……"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님?!","JPN":"先輩！？","ENG":"Shiyoon?!","TWN":"前輩？！"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"시윤 선배? 무슨 일이야!","JPN":"アキヤマ先輩？　どうしたの！？","ENG":"Shiyoon? What's wrong?!","TWN":"時雲前輩？發生什麼事了！"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하... 몸이 움직이지 않는 게, 아무래도 한계가 온 모양이군요.","JPN":"ハハ……どうやら限界が来たようですね。体が動きません。","ENG":"Haha... I can't seem to move. Looks like I've finally reached my limit.","TWN":"哈哈……身體不能動，看來是到極限了。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"잠시 실례하죠.","JPN":"失礼します。","ENG":"Let me take a look.","TWN":"失禮了。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이 상처는...","JPN":"この傷は……","ENG":"This wound...","TWN":"這個傷口是……"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이런 상태로 계속 전투를 이어오신 겁니까?","JPN":"こんな状態で戦闘を続けていたんですか？","ENG":"Have you been continuing to fight in this condition?","TWN":"你一直用這樣的狀態戰鬥嗎？"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"다들 목숨을 걸고 싸우는데... 혼자 엄살을 피울 순 없잖아요.","JPN":"みんな命をかけて戦っているのに……僕だけ弱音を吐くわけにはいかないじゃないですか。","ENG":"Everyone else is risking their lives fighting... I can't be the only one complaining.","TWN":"大家都在拼命……我怎麼能一個人喊痛。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"한 눈에 봐도 심각한데 뭐가 엄살이란 거야?!","JPN":"どう見ても大怪我なのに、何が弱音よ！？","ENG":"Anyone can see how serious that is! What do you mean complaining?!","TWN":"這一看就很嚴重，怎麼還逞強？"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"카운터인 이상 조금이라도 회복의 기미가 보여야 할 텐데, 출혈조차 멎지 않는 건 이상하군요.","JPN":"カウンターである以上、少しでも回復の兆しがなければいけないのですが……出血すら止まらないというのはおかしいですね。","ENG":"As a Counter, there should at least be some sign of recovery, but the fact that even the bleeding hasn't stopped is unusual.","TWN":"作為制裁者，應該會有恢復跡象才對，但連出血都止不住，很奇怪。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"상처에 깃든 신성이 자연치유를 막고 있는 것 같아요.","JPN":"傷に染み込んだ神聖が自然回復を妨げているようです。","ENG":"It seems the Divinity energy embedded in the wound is preventing natural healing.","TWN":"傷口中的神性似乎阻止了自然癒合。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"타기리온과의 교전 때 입은 상처군요.","JPN":"タギリオンとの交戦で負った傷ですね。","ENG":"Those are injuries from your battle with Thagirion.","TWN":"這是和塔基里翁戰鬥時留下的傷。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"응급처치는 해두겠지만, 움직여서는 안 됩니다.","JPN":"応急処置はしておきますが、動いてはいけません。","ENG":"I'll provide emergency treatment, but you must not move.","TWN":"我會先做緊急處理，但你不能再動了。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하지만...","JPN":"ですが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전문가 말을 들으시죠, 시윤 군.","JPN":"専門家の言う通りにしてください、アキヤマ君。","ENG":"Listen to the expert, Shiyoon.","TWN":"聽專業的吧，時雲。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"외근 중에 다치는 것만큼 서러운 일도 없으니까요.","JPN":"出張先で怪我することほど悲しいことはありませんから。","ENG":"There's nothing more miserable than getting injured while out on assignment.","TWN":"沒有比在外勤受傷更痛苦的事了。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"산재 처리 및 장기 요양 급여... 가능할까요?","JPN":"労災……もらえますかね？","ENG":"Do you think... workers' compensation and extended medical leave benefits would be possible?","TWN":"可以申請……職災補助和長期療養嗎？"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"농담을 할 만큼의 여유는 있어 보여서 다행이군요.","JPN":"冗談を叩く余裕があって何よりです。","ENG":"I'm glad to see you still have the composure to make jokes.","TWN":"幸好你看來還有心情開玩笑。"},"stage":{"bg":"PATH","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"멀쩡히 살아서 급여를 받고 싶다면, 얌전히 쉬고 있으세요.","JPN":"無事生きて給料をもらいたいなら、大人しく休んでてください。","ENG":"If you want to stay alive long enough to receive those benefits, stay still and rest.","TWN":"你要想活著領補助，就乖乖休息。"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금부터 현 상황은 관리국이 통제할 테니까요.","JPN":"今から現況は管理局の統制下におかれることになります。","ENG":"From here on, the Administration will take control of the situation.","TWN":"接下來由管理局接管現場。"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"여기는 바루나 전대. 일대의 침식 정화 작업을 마치고 보고한다.","JPN":"こちらヴァルナ戦隊。一帯の侵食浄化作業を終えたことを報告する。","ENG":"This is Varuna Division. Reporting after completing Corruption purification operations in the area.","TWN":"這裡是伐樓拿戰隊，已淨化這一帶的侵蝕作業並回報。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"현재 통신은 정상적으로 회복되었으며, 현장에서 조우한 전대들과 함께 선두에 합류하는 중이다.","JPN":"現在通信は正常に回復し、現場で遭遇した戦隊と共に先頭に合流するために移動中だ。","ENG":"Comms have now been fully restored, and we are joining the vanguard together with the divisions we encountered on site.","TWN":"通訊已恢復正常，正在和現場遇到的戰隊加入前鋒中。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_RA","text":{"KOREA":"고르디우스 전대입니다. 타기리온 권역 내 침식균열 다수의 봉인을 마쳤습니다.","JPN":"ゴルディウス戦隊です。タギリオン圏域内の侵食亀裂を多数封印しました。","ENG":"This is Gordias Division. We have sealed multiple Corruption rifts within Thagirion's territory.","TWN":"這裡是戈爾迪亞戰隊，已完成封印多處侵蝕裂縫。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_RA","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_RA","text":{"KOREA":"본대와 합류할 테니, 조금만 버텨주십시오.","JPN":"本隊と合流しますので、もう少し耐えてください。","ENG":"We'll be joining up with the main force, so please hold out just a little longer.","TWN":"即將與本隊會合，請再撐一下。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_RA","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"전대라면... 구 관리국 출신들?","JPN":"戦隊ってことは……旧管理局出身の？","ENG":"By squads... you mean Old Administration personnel?","TWN":"戰隊的話……？是舊管理局的人？"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":{"char_id":"CHINATSU_NANA_NULL_RA","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"다른 함선에 타고 있던 사람들이 평범한 태스크포스가 아니었단 말이야?!","JPN":"他の艦船に乗ってた人たちって、普通のタスクフォースじゃなかったの！？","ENG":"The people on those other ships weren't just ordinary TASKFORCEs?!","TWN":"其他艦船上的人不是普通的特遣勢力嗎？！"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":{"char_id":"CHINATSU_NANA_NULL_RA","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니...! 들리시나요?! 해당 지점으로 최소 3종 이상의 잔류 침식체들이 접근 중입니다!","JPN":"コフィンカンパニー……！　聞こえていますか！？　該当地点へ最低第3種以上の残留侵食体が複数接近中です！","ENG":"Coffin Company...! Can you hear us?! Residual C.O.s that are at least Category 3 are approaching your position!","TWN":"柯芬公司……聽得到嗎？！至少有3種以上的殘存侵蝕體正接近該地點！"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CHINATSU_NANA_NULL_RA","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네, 잘 보이는군요.","JPN":"はい、見えています。","ENG":"Yes, I can see them clearly.","TWN":"嗯，我們看得很清楚。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"...그 녀석들을 뒤쫓는 포탄도 말이죠.","JPN":"……奴らを追いかける砲弾も。","ENG":"...And the munition chasing after them as well.","TWN":"……還有追在它們身後的砲彈。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_FIRE"},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"...포격이다.","JPN":"……砲撃だ。","ENG":"...Incoming artillery fire.","TWN":"……是砲擊。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"메이즈 전대까지 도착했어!","JPN":"メイズ戦隊も到着した！","ENG":"Maze Division has arrived too!","TWN":"梅茲戰隊也到了！"},"stage":{"bg":"PATH","bgm":"THEMA_CA_SURYA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"}}}}]`);export{e as default};